class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def plusOne(head: ListNode) -> ListNode:
    def add_one_recursive(node: ListNode) -> int:
        if not node:
            return 1

        carry_from_right = add_one_recursive(node.next)

        if carry_from_right == 0:
            return 0

        total_sum = node.val + carry_from_right
        node.val = total_sum % 10

        return total_sum // 10

    final_carry = add_one_recursive(head)

    if final_carry == 1:
        new_head = ListNode(1)
        new_head.next = head
        return new_head
    else:
        return head
